import{_ as t,o as r,c as a,a2 as s}from"./chunks/framework.B72_uj9U.js";const c=JSON.parse('{"title":"Chapter 2: Rust for Python Developers","description":"A bridge from Python to Rust covering ownership, error handling, traits, and async — everything you need to start building in Rust.","frontmatter":{"title":"Chapter 2: Rust for Python Developers","description":"A bridge from Python to Rust covering ownership, error handling, traits, and async — everything you need to start building in Rust."},"headers":[],"relativePath":"learn/linear/02-rust-for-python-developers/index.md","filePath":"learn/linear/02-rust-for-python-developers/index.md"}'),o={name:"learn/linear/02-rust-for-python-developers/index.md"};function i(n,e,l,h,p,u){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="rust-for-python-developers" tabindex="-1">Rust for Python Developers <a class="header-anchor" href="#rust-for-python-developers" aria-label="Permalink to &quot;Rust for Python Developers&quot;">​</a></h1><p>If you are coming from Python, Rust can feel like a different planet. The compiler is strict, there is no garbage collector, and you must think about memory ownership in ways Python never required. But the reward is enormous: zero-cost abstractions, fearless concurrency, and a type system that catches entire classes of bugs at compile time. This chapter bridges the gap by mapping every major Rust concept to its Python equivalent.</p><p>We start with practical setup — installing Rust and understanding Cargo — then work through the language feature by feature. Each section presents the Python way first, then shows how Rust achieves the same goal with its own idioms. Ownership and borrowing are covered in depth because they are the biggest conceptual leap. We then move through structs, enums, traits, generics, and error handling, always drawing explicit parallels to Python classes, protocols, and exception handling.</p><p>By the end of this chapter, you will be able to read and write Rust at a level sufficient to build the coding agent. You will not be a Rust expert, but you will have a working mental model and enough fluency to follow the implementation chapters that come next.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Install Rust and use Cargo to create, build, and test projects</li><li>Understand ownership, borrowing, and lifetimes as alternatives to garbage collection</li><li>Map Python classes to Rust structs and Python protocols to Rust traits</li><li>Handle errors idiomatically with Result and Option instead of try/except</li><li>Write async Rust code using tokio and understand how it compares to Python&#39;s asyncio</li><li>Use Rust&#39;s module system, collections, and iterators with confidence</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/02-rust-for-python-developers/01-why-rust.html">Why Rust</a></li><li><a href="/linear/02-rust-for-python-developers/02-installing-and-setup.html">Installing and Setup</a></li><li><a href="/linear/02-rust-for-python-developers/03-cargo-vs-pip.html">Cargo vs Pip</a></li><li><a href="/linear/02-rust-for-python-developers/04-hello-world.html">Hello World</a></li><li><a href="/linear/02-rust-for-python-developers/05-variables-ownership-vs-python-gc.html">Variables Ownership vs Python GC</a></li><li><a href="/linear/02-rust-for-python-developers/06-borrowing-and-references.html">Borrowing and References</a></li><li><a href="/linear/02-rust-for-python-developers/07-structs-vs-classes.html">Structs vs Classes</a></li><li><a href="/linear/02-rust-for-python-developers/08-enums-and-pattern-matching.html">Enums and Pattern Matching</a></li><li><a href="/linear/02-rust-for-python-developers/09-error-handling-result-vs-try-except.html">Error Handling Result vs Try Except</a></li><li><a href="/linear/02-rust-for-python-developers/10-traits-vs-protocols.html">Traits vs Protocols</a></li><li><a href="/linear/02-rust-for-python-developers/11-generics.html">Generics</a></li><li><a href="/linear/02-rust-for-python-developers/12-modules-and-crates.html">Modules and Crates</a></li><li><a href="/linear/02-rust-for-python-developers/13-strings-in-rust.html">Strings in Rust</a></li><li><a href="/linear/02-rust-for-python-developers/14-collections.html">Collections</a></li><li><a href="/linear/02-rust-for-python-developers/15-iterators-vs-comprehensions.html">Iterators vs Comprehensions</a></li><li><a href="/linear/02-rust-for-python-developers/16-async-await.html">Async Await</a></li><li><a href="/linear/02-rust-for-python-developers/17-testing.html">Testing</a></li><li><a href="/linear/02-rust-for-python-developers/18-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Python programming experience — you should be comfortable writing functions, classes, and using pip</li><li>A terminal you are familiar with (bash, zsh, PowerShell, etc.)</li><li>No prior Rust experience required — this chapter starts from zero</li></ul>',10)])])}const f=t(o,[["render",i]]);export{c as __pageData,f as default};
